1	import type * as http from 'node:http';
2	import { MAX_FRAME, type ChatContext, type HookBus } from '@ax/core';
3	import {
4	  internalError,
5	  logInternalError,
6	  notFound,
7	} from './errors.js';
8	import {
9	  BadJsonError,
10	  readJsonBody,
11	  TooLargeError,
12	} from './body.js';
13	import { writeJsonError, writeJsonOk } from './response.js';
14	import type { HandlerResult, HandlerErr, HandlerOk } from './handlers/types.js';
15	import { llmCallHandler } from './handlers/llm-call.js';
16	import { toolPreCallHandler } from './handlers/tool-pre-call.js';
17	import { toolExecuteHostHandler } from './handlers/tool-execute-host.js';
18	import { toolListHandler } from './handlers/tool-list.js';
19	import { workspaceCommitNotifyHandler } from './handlers/workspace-commit-notify.js';
20	import { sessionNextMessageHandler } from './handlers/session-next-message.js';
21	import {
22	  validateEventToolPostCall,
23	  fireEventToolPostCall,
24	} from './handlers/event-tool-post-call.js';
25	import {
26	  validateEventTurnEnd,
27	  fireEventTurnEnd,
28	} from './handlers/event-turn-end.js';
29	import {
30	  validateEventChatEnd,
31	  fireEventChatEnd,
32	} from './handlers/event-chat-end.js';
33	import { streamChunkNotWired } from './handlers/event-stream-chunk.js';
34	
35	// ---------------------------------------------------------------------------
36	// Dispatcher
37	//
38	// Routes authenticated+authorized inbound requests to per-action handlers.
39	// The listener already ran all five inbound gates (method, content-type,
40	// auth, cross-session, body-size fail-fast) before we're invoked. The
41	// dispatcher's job is strictly: pick a handler by (method, path), read the
42	// body, run the handler, write the response.
43	//
44	// Two handler shapes:
45	//   - ACTIONS (POST/GET with synchronous response): readJsonBody → handler
46	//     → write response. Handler returns {status, body}.
47	//   - EVENTS (POST, fire-and-forget 202): readJsonBody → validator →
48	//     write 202 → fire subscriber asynchronously. Subscriber failures are
49	//     logged but NEVER reach the client (D4: events are fire-and-forget).
50	//
51	// Unknown path → 404 VALIDATION. Body-parsing errors bubble up to this
52	// function's try/catch and become 4xx/5xx per the readJsonBody contract
53	// (the listener's gate already covered the fail-fast Content-Length case;
54	// mid-stream overflow still possible here if the client streams a body
55	// with a lying Content-Length).
56	// ---------------------------------------------------------------------------
57	
58	const ACTIONS = new Map<string, {
59	  method: 'POST';
60	  handler: typeof llmCallHandler;
61	}>();
62	ACTIONS.set('/llm.call', { method: 'POST', handler: llmCallHandler });
63	ACTIONS.set('/tool.pre-call', { method: 'POST', handler: toolPreCallHandler });
64	ACTIONS.set('/tool.execute-host', { method: 'POST', handler: toolExecuteHostHandler });
65	ACTIONS.set('/tool.list', { method: 'POST', handler: toolListHandler });
66	ACTIONS.set('/workspace.commit-notify', { method: 'POST', handler: workspaceCommitNotifyHandler });
67	
68	type EventSpec = {
69	  method: 'POST';
70	  validate: (payload: unknown) =>
71	    | { ok: true; payload: unknown }
72	    | HandlerErr;
73	  fire: (ctx: ChatContext, bus: HookBus, payload: unknown) => Promise<void>;
74	};
75	
76	const EVENTS = new Map<string, EventSpec>();
77	EVENTS.set('/event.tool-post-call', {
78	  method: 'POST',
79	  validate: validateEventToolPostCall,
80	  fire: fireEventToolPostCall,
81	});
82	EVENTS.set('/event.turn-end', {
83	  method: 'POST',
84	  validate: validateEventTurnEnd,
85	  fire: fireEventTurnEnd,
86	});
87	EVENTS.set('/event.chat-end', {
88	  method: 'POST',
89	  validate: validateEventChatEnd,
90	  fire: fireEventChatEnd,
91	});
92	
93	function isErr(r: HandlerResult): r is HandlerErr {
94	  // An OK body is whatever the handler returned; the error body has the
95	  // { error: { code, message } } envelope. We treat any result with that
96	  // envelope as an error so the dispatcher writes via writeJsonError and
97	  // the logger stays at the right level.
98	  const body = (r as HandlerOk).body as { error?: unknown } | undefined;
99	  return (
100	    body !== undefined &&
101	    body !== null &&
102	    typeof body === 'object' &&
103	    'error' in body &&
104	    typeof (body as { error: unknown }).error === 'object'
105	  );
106	}
107	
108	async function readBodyOrWriteError(
109	  req: http.IncomingMessage,
110	  res: http.ServerResponse,
111	): Promise<{ ok: true; value: unknown } | { ok: false }> {
112	  try {
113	    const { value } = await readJsonBody(req, MAX_FRAME);
114	    return { ok: true, value };
115	  } catch (err) {
116	    if (err instanceof TooLargeError) {
117	      if (!res.headersSent) {
118	        try {
119	          res.setHeader('Connection', 'close');
120	        } catch {
121	          // Response already closed.
122	        }
123	      }
124	      writeJsonError(res, 413, 'VALIDATION', 'body too large');
125	      return { ok: false };
126	    }
127	    if (err instanceof BadJsonError) {
128	      writeJsonError(res, 400, 'VALIDATION', `invalid json: ${err.message}`);
129	      return { ok: false };
130	    }
131	    throw err;
132	  }
133	}
134	
135	function writeResult(res: http.ServerResponse, result: HandlerResult): void {
136	  if (isErr(result)) {
137	    writeJsonError(res, result.status, result.body.error.code, result.body.error.message);
138	    return;
139	  }
140	  writeJsonOk(res, result.status, result.body);
141	}
142	
143	export async function dispatch(
144	  req: http.IncomingMessage,
145	  res: http.ServerResponse,
146	  ctx: ChatContext,
147	  bus: HookBus,
148	): Promise<void> {
149	  // Parse path off the URL. Node gives us `req.url` as a path+query string;
150	  // we join it onto a dummy origin so URL() can split searchParams safely.
151	  const rawUrl = req.url ?? '/';
152	  const url = new URL(rawUrl, 'http://ipc.local');
153	  const pathname = url.pathname;
154	  const method = req.method;
155	
156	  // ----- GET /session.next-message (only GET in the protocol) -----
157	  if (pathname === '/session.next-message') {
158	    if (method !== 'GET') {
159	      writeJsonError(res, 405, 'VALIDATION', 'method not allowed');
160	      return;
161	    }
162	    try {
163	      const result = await sessionNextMessageHandler(url, ctx, bus);
164	      writeResult(res, result);
165	    } catch (err) {
166	      logInternalError(ctx.logger, 'session.next-message', err);
167	      if (!res.headersSent) {
168	        const fallback = internalError();
169	        writeJsonError(res, fallback.status, fallback.body.error.code, fallback.body.error.message);
170	      }
171	    }
172	    return;
173	  }
174	
175	  // ----- event.stream-chunk — 6.5a: always 501 -----
