1	import * as http from 'node:http';
2	import { z } from 'zod';
3	import {
4	  IPC_TIMEOUTS_MS,
5	  IpcErrorEnvelopeSchema,
6	  LlmCallResponseSchema,
7	  SessionNextMessageResponseSchema,
8	  ToolExecuteHostResponseSchema,
9	  ToolListResponseSchema,
10	  ToolPreCallResponseSchema,
11	  WorkspaceCommitNotifyResponseSchema,
12	  type IpcActionName,
13	} from '@ax/ipc-protocol';
14	import {
15	  HostUnavailableError,
16	  IpcRequestError,
17	  SessionInvalidError,
18	} from './errors.js';
19	
20	// ---------------------------------------------------------------------------
21	// Sandbox-side IPC client. Speaks HTTP over either a unix socket OR a TCP
22	// connection — the caller hands us a `runnerEndpoint` URI and we pick the
23	// transport from the scheme.
24	//
25	// Supported schemes today:
26	//   - `unix:///abs/path/ipc.sock` — the in-host subprocess sandbox provider.
27	//                                   Connects via http.request({ socketPath }).
28	//   - `http://host:port`          — RESERVED for the k8s pod sandbox
29	//                                   provider (Task 14). NOT IMPLEMENTED YET:
30	//                                   passing one will throw at construction
31	//                                   time. The pod's HTTP server side is the
32	//                                   missing half of this story; once it
33	//                                   exists, the unix:// branch and the http://
34	//                                   branch share the same retry/backoff/cap
35	//                                   logic — only the http.request options
36	//                                   differ.
37	//
38	// Three methods:
39	//
40	//   call(action, payload)    — POST /<action> with a JSON body. Response is
41	//                              Zod-parsed using the matching schema from
42	//                              @ax/ipc-protocol (lookup table below).
43	//
44	//   callGet(action, query)   — GET /<action>?k=v&.... Only used for
45	//                              session.next-message today; typed narrowly
46	//                              so misuse is a compile error.
47	//
48	//   event(name, payload)     — POST /<name> fire-and-forget. Resolves on
49	//                              202; connection-level errors reject, but
50	//                              callers usually log and move on.
51	//
52	// Retry and timeout policy lives in this file:
53	//   - 5xx + connection errors → retry, exponential backoff, cap maxRetries.
54	//   - 401 → SessionInvalidError (terminal).
55	//   - 400/404/409 → IpcRequestError (don't retry).
56	//   - Per-action timeout from IPC_TIMEOUTS_MS (overridable for tests).
57	//
58	// Response-body cap: we drain into a Buffer capped at MAX_RESPONSE_BYTES.
59	// @ax/core has a MAX_FRAME of 4 MiB, but this package must not import the
60	// kernel (sandbox-side), so we redeclare the same ceiling here. Task 14
61	// may unify if that boundary shifts.
62	// ---------------------------------------------------------------------------
63	
64	const MAX_RESPONSE_BYTES = 4 * 1024 * 1024;
65	
66	// Dispatch table: action → Zod schema for the successful response body.
67	// Event endpoints have no response body (just {accepted: true} on 202) and
68	// are handled separately in `event()`.
69	const RESPONSE_SCHEMAS: Record<IpcActionName, z.ZodTypeAny> = {
70	  'llm.call': LlmCallResponseSchema,
71	  'tool.pre-call': ToolPreCallResponseSchema,
72	  'tool.execute-host': ToolExecuteHostResponseSchema,
73	  'tool.list': ToolListResponseSchema,
74	  'workspace.commit-notify': WorkspaceCommitNotifyResponseSchema,
75	  'session.next-message': SessionNextMessageResponseSchema,
76	};
77	
78	export interface IpcClientOptions {
79	  /**
80	   * Opaque URI the runner uses to reach the host. Schemes:
81	   *   - `unix:///abs/path` — connects to a Unix domain socket at the path.
82	   *   - `http://host:port` — TCP HTTP. NOT IMPLEMENTED YET (Task 14).
83	   *
84	   * The runner doesn't pick the scheme — the sandbox provider does, and
85	   * sets AX_RUNNER_ENDPOINT in the runner's env. See @ax/sandbox-subprocess
86	   * (`unix://`) and @ax/sandbox-k8s (`http://`).
87	   */
88	  runnerEndpoint: string;
89	  token: string;
90	  /** Defaults from @ax/ipc-protocol IPC_TIMEOUTS_MS. Tests override. */
91	  timeouts?: Partial<Record<IpcActionName, number>>;
92	  /** Defaults to an exponential-backoff schedule (100 → 30_000 ms cap). */
93	  retryBackoff?: (attempt: number) => number;
94	  /** Max retry attempts on connection-level errors / 5xx. Default: 5. */
95	  maxRetries?: number;
96	  /** Testable seam. */
97	  now?: () => number;
98	}
99	
100	/**
101	 * Parsed transport-target derived from `runnerEndpoint`. The two shapes
102	 * line up with the two argument forms of `http.request()`.
103	 */
104	type TransportTarget =
105	  | { kind: 'unix'; socketPath: string }
106	  | { kind: 'http'; host: string; port: number };
107	
108	function parseRunnerEndpoint(uri: string): TransportTarget {
109	  let url: URL;
110	  try {
111	    url = new URL(uri);
112	  } catch (cause) {
113	    throw new HostUnavailableError(
114	      `invalid runnerEndpoint URI: ${uri}`,
115	      cause as Error,
116	    );
117	  }
118	  switch (url.protocol) {
119	    case 'unix:': {
120	      // unix:///abs/path → url.pathname = '/abs/path'. We require an absolute
121	      // path; relative would mean "unix:relative/path" (no slashes), which we
122	      // reject as an obvious wiring bug.
123	      const socketPath = url.pathname;
124	      if (socketPath.length === 0 || !socketPath.startsWith('/')) {
125	        throw new HostUnavailableError(
126	          `unix:// runnerEndpoint must include an absolute path (got ${uri})`,
127	        );
128	      }
129	      return { kind: 'unix', socketPath };
130	    }
131	    case 'http:': {
132	      // http transport is reserved for @ax/sandbox-k8s. The pod's HTTP server
133	      // half doesn't exist yet — surface a clear error rather than try to
134	      // connect to a non-existent listener and then mislead the operator with
135	      // "ECONNREFUSED" later.
136	      throw new HostUnavailableError(
137	        'http:// runnerEndpoint is not implemented yet (Task 14 deliverable). ' +
138	          'Use unix:// for the subprocess sandbox.',
139	      );
140	    }
141	    default:
142	      throw new HostUnavailableError(
143	        `unsupported runnerEndpoint scheme: ${url.protocol}`,
144	      );
145	  }
146	}
147	
148	export interface IpcClient {
149	  call<Action extends IpcActionName>(
150	    action: Action,
151	    payload: unknown,
152	  ): Promise<unknown>;
153	
154	  callGet<Action extends 'session.next-message'>(
155	    action: Action,
156	    query: Record<string, string>,
157	  ): Promise<unknown>;
158	
159	  event(eventName: string, payload: unknown): Promise<void>;
160	
161	  close(): Promise<void>;
162	}
163	
164	// Connection-level errors that should be treated as HostUnavailableError.
165	// We also catch the unix-socket-file-missing case (ENOENT on connect).
166	const TRANSIENT_ERRNOS = new Set<string>([
167	  'ECONNREFUSED',
168	  'ECONNRESET',
169	  'EPIPE',
170	  'ENOENT',
171	  'ENOTFOUND',
172	  'EHOSTUNREACH',
173	  'ENETUNREACH',
174	  'ETIMEDOUT',
175	]);
176	
177	function isTransientConnectionError(err: unknown): boolean {
178	  if (err instanceof HostUnavailableError) return true;
179	  const code = (err as NodeJS.ErrnoException | undefined)?.code;
180	  return code !== undefined && TRANSIENT_ERRNOS.has(code);
181	}
182	
183	function defaultBackoff(attempt: number): number {
184	  // 100, 200, 400, 800, 1600, ... capped at 30s. `attempt` is 0-indexed so
185	  // the first retry waits 100 ms.
186	  return Math.min(100 * 2 ** attempt, 30_000);
187	}
188	
189	interface RawResponse {
190	  status: number;
191	  body: Buffer;
192	}
193	
194	/**
195	 * One attempt — issues the HTTP request, returns the raw status+body, or
196	 * throws a HostUnavailableError for connection-level / timeout failures.
197	 *
198	 * Does NOT apply retry policy. Does NOT Zod-parse. Caller wraps.
199	 */
200	function requestOnce(
201	  opts: {
202	    target: TransportTarget;
203	    method: 'GET' | 'POST';
204	    pathWithQuery: string;
205	    token: string;
206	    body?: Buffer;
207	    timeoutMs: number;
208	  },
209	): Promise<RawResponse> {
210	  return new Promise<RawResponse>((resolve, reject) => {
211	    const controller = new AbortController();
212	    const timer = setTimeout(() => {
213	      controller.abort();
214	    }, opts.timeoutMs);
215	
216	    const headers: Record<string, string> = {
217	      Authorization: `Bearer ${opts.token}`,
218	    };
219	    if (opts.body !== undefined) {
220	      headers['Content-Type'] = 'application/json';
221	      headers['Content-Length'] = String(opts.body.length);
222	    }
223	
224	    let settled = false;
225	    const settle = (fn: () => void): void => {
226	      if (settled) return;
227	      settled = true;
228	      clearTimeout(timer);
229	      fn();
230	    };
231	
232	    // Defensive: parseRunnerEndpoint rejects http:// at construction time
233	    // today; if a future caller adds a new scheme we want a loud,
234	    // localized error rather than a confusing connect failure deep in
235	    // node:http.
236	    if (opts.target.kind !== 'unix') {
237	      settle(() =>
238	        reject(
239	          new HostUnavailableError(
240	            `transport ${opts.target.kind} not implemented`,
241	          ),
242	        ),
243	      );
244	      return;
245	    }
246	
247	    const req = http.request(
248	      {
249	        socketPath: opts.target.socketPath,
250	        path: opts.pathWithQuery,
251	        method: opts.method,
252	        headers,
253	        signal: controller.signal,
254	      },
255	      (res) => {
256	        const chunks: Buffer[] = [];
257	        let total = 0;
258	        let overflowed = false;
259	        res.on('data', (chunk: Buffer) => {
260	          total += chunk.length;
261	          if (total > MAX_RESPONSE_BYTES) {
262	            if (!overflowed) {
263	              overflowed = true;
264	              // Destroying the response ends the stream; we'll surface a
265	              // HostUnavailableError on 'error' (NOT 'end' — res.destroy(err)
266	              // emits 'error' and 'close', not 'end').
267	              res.destroy(new Error('response body too large'));
268	            }
269	            return;
270	          }
271	          chunks.push(chunk);
272	        });
273	        res.on('end', () => {
274	          // By the time 'end' fires, no destroy has run — resolve normally.
275	          settle(() =>
276	            resolve({ status: res.statusCode ?? 0, body: Buffer.concat(chunks) }),
277	          );
278	        });
279	        res.on('error', (err) => {
280	          // Overflow path funnels through here (res.destroy was called with
281	          // a 'response body too large' error). Translate to a specific
282	          // HostUnavailableError message so callers see the real reason
283	          // instead of a generic "stream error."
284	          const message = overflowed
285	            ? 'response body exceeded cap'
286	            : 'response stream error';
287	          settle(() => reject(new HostUnavailableError(message, err)));
288	        });
289	      },
290	    );
291	
292	    req.on('error', (err) => {
293	      // AbortController.abort() surfaces as an 'AbortError' here; treat as
294	      // timeout specifically so the message is useful.
295	      const errno = (err as NodeJS.ErrnoException).code;
296	      if ((err as Error).name === 'AbortError' || errno === 'ABORT_ERR') {
297	        settle(() => reject(new HostUnavailableError('timeout', err)));
298	        return;
299	      }
300	      if (errno !== undefined && TRANSIENT_ERRNOS.has(errno)) {
301	        settle(() => reject(new HostUnavailableError(`connect failed: ${errno}`, err)));
302	        return;
303	      }
304	      settle(() => reject(new HostUnavailableError(`request failed: ${(err as Error).message}`, err)));
305	    });
306	
307	    if (opts.body !== undefined) req.write(opts.body);
308	    req.end();
309	  });
310	}
311	
312	function toQueryString(query: Record<string, string>): string {
313	  const params = new URLSearchParams();
314	  for (const [k, v] of Object.entries(query)) params.append(k, v);
315	  const s = params.toString();
316	  return s.length === 0 ? '' : `?${s}`;
317	}
318	
319	function parseErrorEnvelope(
320	  status: number,
321	  body: Buffer,
322	): IpcRequestError | SessionInvalidError {
323	  // Best-effort — if the body isn't a valid error envelope, synthesize a
324	  // generic message so callers always get a useful error.
325	  let code = 'INTERNAL';
326	  let message = `request failed with status ${status}`;
327	  try {
328	    const parsed = IpcErrorEnvelopeSchema.parse(JSON.parse(body.toString('utf8')));
329	    code = parsed.error.code;
330	    message = parsed.error.message;
331	  } catch {
332	    // Leave defaults.
333	  }
334	  if (status === 401) return new SessionInvalidError(message);
335	  return new IpcRequestError(code, status, message);
336	}
337	
338	export function createIpcClient(opts: IpcClientOptions): IpcClient {
339	  const maxRetries = opts.maxRetries ?? 5;
340	  const backoff = opts.retryBackoff ?? defaultBackoff;
341	  // Resolve the transport target ONCE at construction. parseRunnerEndpoint
342	  // throws HostUnavailableError on an invalid URI / http:// scheme — that
343	  // surfaces immediately at runner-startup, not on the first IPC call,
344	  // which is the right time to fail loud.
345	  const target = parseRunnerEndpoint(opts.runnerEndpoint);
346	
347	  const timeoutFor = (action: IpcActionName): number => {
348	    if (opts.timeouts?.[action] !== undefined) return opts.timeouts[action]!;
349	    // For long-poll endpoints, the server-side deadline IS IPC_TIMEOUTS_MS
350	    // (the server holds the request open for that long). If the client aborts
351	    // at the same value, a race window exists where the client's abort fires
352	    // just as the server is about to return `{type:'timeout'}` — producing a
353	    // spurious HostUnavailableError instead of a clean timeout response the
354	    // inbox loop knows how to handle. Add a grace period on top so the
355	    // server always responds first.
356	    if (action === 'session.next-message') {
357	      return IPC_TIMEOUTS_MS[action] + 5_000;
358	    }
359	    return IPC_TIMEOUTS_MS[action];
360	  };
361	
362	  // Retry loop. `shouldRetry` decides whether the error is transient and
363	  // another attempt is warranted. We run up to `maxRetries + 1` total
364	  // attempts (the initial + N retries).
365	  const withRetry = async <T>(
366	    shouldRetry: (err: unknown) => boolean,
367	    fn: () => Promise<T>,
368	  ): Promise<T> => {
369	    let lastErr: unknown;
370	    for (let attempt = 0; attempt <= maxRetries; attempt++) {
371	      try {
372	        return await fn();
373	      } catch (err) {
374	        lastErr = err;
375	        if (!shouldRetry(err) || attempt === maxRetries) throw err;
376	        const wait = backoff(attempt);
377	        if (wait > 0) {
378	          await new Promise<void>((resolve) => setTimeout(resolve, wait));
379	        }
380	      }
381	    }
382	    // Unreachable — the for-loop either returns or throws before falling out.
383	    // The `throw` here is defensive to satisfy the control-flow analyzer.
384	    throw lastErr;
385	  };
386	
387	  const parseSuccessBody = (action: IpcActionName, body: Buffer): unknown => {
388	    const schema = RESPONSE_SCHEMAS[action];
389	    let json: unknown;
390	    try {
391	      json = JSON.parse(body.toString('utf8'));
392	    } catch (err) {
393	      // Malformed JSON from the host is a host-side bug, not a client bug.
394	      // We don't classify it as retryable — surfacing quickly is the point.
395	      throw new IpcRequestError(
396	        'INTERNAL',
397	        0,
398	        `invalid json response: ${(err as Error).message}`,
399	      );
400	    }
401	    const result = schema.safeParse(json);
402	    if (!result.success) {
403	      throw new IpcRequestError(
404	        'INTERNAL',
405	        0,
406	        `response validation failed: ${result.error.message}`,
407	      );
408	    }
409	    return result.data;
410	  };
411	
412	  const call = async <Action extends IpcActionName>(
413	    action: Action,
414	    payload: unknown,
415	  ): Promise<unknown> => {
416	    const body = Buffer.from(JSON.stringify(payload), 'utf8');
417	    const timeoutMs = timeoutFor(action);
418	
419	    return withRetry(
420	      // Retry on transient (connection-level / timeout) + 5xx responses.
421	      (err) => {
422	        if (isTransientConnectionError(err)) return true;
423	        if (err instanceof IpcRequestError && err.status >= 500) return true;
424	        return false;
425	      },
426	      async () => {
427	        const raw = await requestOnce({
428	          target,
429	          method: 'POST',
430	          pathWithQuery: `/${action}`,
431	          token: opts.token,
432	          body,
433	          timeoutMs,
434	        });
435	        if (raw.status >= 200 && raw.status < 300) {
436	          return parseSuccessBody(action, raw.body);
437	        }
438	        throw parseErrorEnvelope(raw.status, raw.body);
439	      },
440	    );
441	  };
442	
443	  const callGet = async <Action extends 'session.next-message'>(
444	    action: Action,
445	    query: Record<string, string>,
446	  ): Promise<unknown> => {
447	    const timeoutMs = timeoutFor(action);
448	    const pathWithQuery = `/${action}${toQueryString(query)}`;
449	
450	    return withRetry(
451	      (err) => {
452	        if (isTransientConnectionError(err)) return true;
453	        if (err instanceof IpcRequestError && err.status >= 500) return true;
454	        return false;
455	      },
456	      async () => {
457	        const raw = await requestOnce({
458	          target,
459	          method: 'GET',
460	          pathWithQuery,
461	          token: opts.token,
462	          timeoutMs,
463	        });
464	        if (raw.status >= 200 && raw.status < 300) {
465	          return parseSuccessBody(action, raw.body);
466	        }
467	        throw parseErrorEnvelope(raw.status, raw.body);
468	      },
469	    );
470	  };
471	
472	  const event = async (eventName: string, payload: unknown): Promise<void> => {
473	    const body = Buffer.from(JSON.stringify(payload), 'utf8');
474	    // Events are fire-and-forget on the wire (202). They still need a
475	    // timeout so a wedged socket doesn't hang the runner forever. Pick a
476	    // sane short ceiling — 10 s matches tool.pre-call.
477	    const timeoutMs = 10_000;
478	    const raw = await requestOnce({
479	      target,
480	      method: 'POST',
481	      pathWithQuery: `/${eventName}`,
482	      token: opts.token,
483	      body,
484	      timeoutMs,
485	    });
486	    if (raw.status === 202) return;
487	    if (raw.status >= 200 && raw.status < 300) return; // tolerate other 2xx
488	    throw parseErrorEnvelope(raw.status, raw.body);
489	  };
490	
491	  const close = async (): Promise<void> => {
492	    // No persistent agent held — each request creates/tears down its own
493	    // http.ClientRequest. Close is a no-op today but reserved for a future
494	    // keep-alive agent if we ever need it.
495	  };
496	
497	  return { call, callGet, event, close };
498	}
