    .call<IpcStopInput, Record<string, never>>('ipc:stop', ctx, {
      sessionId: created.sessionId,
    })
    .catch(() => undefined);
  await bus
    .call<SessionTerminateInput, Record<string, never>>('session:terminate', ctx, {
      sessionId: created.sessionId,
    })
