1	import { createRequire } from 'node:module';
2	import type { Plugin } from '@ax/core';
3	import { createDatabasePostgresPlugin } from '@ax/database-postgres';
4	import { createStoragePostgresPlugin } from '@ax/storage-postgres';
5	import { createEventbusPostgresPlugin } from '@ax/eventbus-postgres';
6	import { createSessionPostgresPlugin } from '@ax/session-postgres';
7	import { createWorkspaceGitPlugin } from '@ax/workspace-git';
8	import { createSandboxK8sPlugin } from '@ax/sandbox-k8s';
9	import { createLlmAnthropicPlugin } from '@ax/llm-anthropic';
10	import { createLlmProxyAnthropicFormatPlugin } from '@ax/llm-proxy-anthropic-format';
11	import { createChatOrchestratorPlugin } from '@ax/chat-orchestrator';
12	import { createToolDispatcherPlugin } from '@ax/tool-dispatcher';
13	import { createToolBashPlugin } from '@ax/tool-bash';
14	import { createToolFileIoPlugin } from '@ax/tool-file-io';
15	import { auditLogPlugin } from '@ax/audit-log';
16	import { createMcpClientPlugin } from '@ax/mcp-client';
17	import { createCredentialsPlugin } from '@ax/credentials';
18	import { createIpcServerPlugin } from '@ax/ipc-server';
19	
20	// ---------------------------------------------------------------------------
21	// @ax/preset-k8s — production assembly: postgres trio + workspace-git +
22	// sandbox-k8s + claude-sdk runner.
23	//
24	// Per architecture doc Section 9, a preset is a meta-package: bumping its
25	// version ships a coordinated release of "k8s mode is now this set of plugin
26	// versions." The runtime contribution is `createK8sPlugins(config)`, which
27	// returns the assembled plugin list ready for `bootstrap()`.
28	//
29	// Why this lives in a preset and not the CLI:
30	//   - The CLI assembles the LOCAL profile (sqlite + sandbox-subprocess +
31	//     session-inmemory). That set is fine for a single laptop and the canary
32	//     test, but it can't run multi-replica because session/storage/eventbus
33	//     are in-process.
34	//   - The k8s profile swaps in the postgres trio (cross-process state),
35	//     workspace-git (durable workspace versioning), and sandbox-k8s (pods
36	//     instead of subprocesses).
37	//   - The CLI is the one place permitted to import plugins directly
38	//     (eslint allowlist); presets/** is in the same allowlist for the same
39	//     reason — they exist to compose plugins.
40	//
41	// Order matters for plugin loading. The kernel tops-sorts on declared
42	// calls/registers, but pushing in a sensible order keeps the intent obvious
43	// to readers. We mirror the CLI's order for the equivalent plugins:
44	//   1. database / storage / credentials (stateful base layer)
45	//   2. eventbus / session (cross-process coordination)
46	//   3. workspace (versioned content)
47	//   4. audit-log (subscribes to chat:end; calls storage:set)
48	//   5. sandbox / ipc-server / llm-proxy / chat-orchestrator (control plane)
49	//   6. tool-dispatcher → tool descriptors → mcp-client (catalog assembly)
50	//   7. llm-anthropic (last; everything else is in place when init runs)
51	// ---------------------------------------------------------------------------
52	
53	const requireFromPreset = createRequire(import.meta.url);
54	
55	/**
56	 * Default location of the claude-sdk runner binary. Resolved against the
57	 * preset's own URL so pnpm hoisting and prod/dev installs both work.
58	 */
59	function defaultRunnerBinary(): string {
60	  return requireFromPreset.resolve('@ax/agent-claude-sdk-runner');
61	}
62	
63	const DEFAULT_CHAT_TIMEOUT_MS = 10 * 60_000;
64	
65	export interface K8sPresetConfig {
66	  /**
67	   * Postgres pool config used by @ax/database-postgres + @ax/storage-postgres.
68	   * (Storage doesn't take its own connection — it reaches the shared pool
69	   * via `database:get-instance`.)
70	   */
71	  database: {
72	    connectionString: string;
73	    poolMax?: number;
74	  };
75	  /**
76	   * Eventbus opens its OWN dedicated pg.Client for LISTEN/NOTIFY — pooled
77	   * connections can't hold a LISTEN binding through idle returns. So this
78	   * is intentionally a separate connectionString (typically the same DSN).
79	   */
80	  eventbus: {
81	    connectionString: string;
82	  };
83	  /**
84	   * Same deal: session-postgres opens its own pool + listen client because
85	   * inbox claim-work blocks on LISTEN. Configured separately.
86	   */
87	  session: {
88	    connectionString: string;
89	    poolMax?: number;
90	  };
91	  /**
92	   * Absolute path to the directory hosting `<repoRoot>/repo.git`. The
93	   * workspace-git plugin idempotently `git init`s it on first use.
94	   */
95	  workspace: {
96	    repoRoot: string;
97	  };
98	  /**
99	   * Pod template + readiness/limits config for sandbox-k8s. All fields
100	   * optional; defaults live in @ax/sandbox-k8s/src/config.ts.
101	   */
102	  sandbox?: {
103	    namespace?: string;
104	    image?: string;
105	    runtimeClassName?: string;
106	    imagePullSecrets?: string[];
107	    cpuLimit?: string;
108	    memoryLimit?: string;
109	    cpuRequest?: string;
110	    memoryRequest?: string;
111	    activeDeadlineSeconds?: number;
112	    readinessPollMs?: number;
113	    readinessTimeoutMs?: number;
114	  };
115	  /**
116	   * Anthropic LLM config. ANTHROPIC_API_KEY must be in env at plugin init
117	   * (the plugin throws otherwise — secrets stay out of the config).
118	   */
119	  anthropic?: {
120	    model?: string;
121	    maxTokens?: number;
122	  };
123	  /**
124	   * Chat orchestrator overrides. `runnerBinary` defaults to the resolved
125	   * @ax/agent-claude-sdk-runner; tests/embedders may override it.
126	   */
127	  chat?: {
128	    runnerBinary?: string;
129	    chatTimeoutMs?: number;
130	    oneShot?: boolean;
131	  };
132	}
133	
134	/**
135	 * Build the production plugin list for k8s mode. Pass the result straight to
136	 * `bootstrap({ bus, plugins, config: {} })` from @ax/core.
137	 *
138	 * Note: the runner binary resolution and Anthropic API key both rely on
139	 * runtime environment (the binary lookup walks node_modules, the API key
140	 * comes from process.env). That's intentional — secrets and resolved paths
141	 * are not in the JSON config schema.
142	 */
143	export function createK8sPlugins(config: K8sPresetConfig): Plugin[] {
144	  const plugins: Plugin[] = [];
145	
146	  // ----- 1. stateful base layer ------------------------------------------
147	  // database-postgres owns the shared pg.Pool. storage-postgres reaches it
148	  // via `database:get-instance` (not a direct import — invariant I2).
149	  plugins.push(
150	    createDatabasePostgresPlugin({
151	      connectionString: config.database.connectionString,
152	      ...(config.database.poolMax !== undefined
153	        ? { poolMax: config.database.poolMax }
154	        : {}),
155	    }),
156	  );
157	  plugins.push(createStoragePostgresPlugin());
158	
159	  // Credentials sits immediately after storage (it calls storage:get/set).
160	  // Init throws if AX_CREDENTIALS_KEY isn't in env.
161	  plugins.push(createCredentialsPlugin());
162	
163	  // ----- 2. cross-process coordination ----------------------------------
164	  // Eventbus and session each own a dedicated LISTEN client.
165	  plugins.push(
166	    createEventbusPostgresPlugin({
167	      connectionString: config.eventbus.connectionString,
168	    }),
169	  );
170	  plugins.push(
171	    createSessionPostgresPlugin({
172	      connectionString: config.session.connectionString,
173	      ...(config.session.poolMax !== undefined
174	        ? { poolMax: config.session.poolMax }
175	        : {}),
176	    }),
177	  );
178	
179	  // ----- 3. workspace ----------------------------------------------------
180	  plugins.push(
181	    createWorkspaceGitPlugin({
182	      repoRoot: config.workspace.repoRoot,
183	    }),
184	  );
185	
186	  // ----- 4. audit log ----------------------------------------------------
187	  // Subscribes to chat:end and writes a record via storage:set. Pushed
188	  // before the chat-orchestrator so its subscription is in place when the
189	  // first chat:end fires.
190	  plugins.push(auditLogPlugin());
191	
192	  // ----- 5. control plane ------------------------------------------------
193	  // sandbox-k8s registers `sandbox:open-session`. No subprocess fallback
194	  // here — this preset is k8s-only.
195	  const sandboxOpts = {
196	    ...(config.sandbox?.namespace !== undefined
197	      ? { namespace: config.sandbox.namespace }
198	      : {}),
199	    ...(config.sandbox?.image !== undefined
200	      ? { image: config.sandbox.image }
201	      : {}),
202	    ...(config.sandbox?.runtimeClassName !== undefined
203	      ? { runtimeClassName: config.sandbox.runtimeClassName }
204	      : {}),
205	    ...(config.sandbox?.imagePullSecrets !== undefined
206	      ? { imagePullSecrets: config.sandbox.imagePullSecrets }
207	      : {}),
208	    ...(config.sandbox?.cpuLimit !== undefined
209	      ? { cpuLimit: config.sandbox.cpuLimit }
210	      : {}),
211	    ...(config.sandbox?.memoryLimit !== undefined
212	      ? { memoryLimit: config.sandbox.memoryLimit }
213	      : {}),
214	    ...(config.sandbox?.cpuRequest !== undefined
215	      ? { cpuRequest: config.sandbox.cpuRequest }
216	      : {}),
217	    ...(config.sandbox?.memoryRequest !== undefined
218	      ? { memoryRequest: config.sandbox.memoryRequest }
219	      : {}),
220	    ...(config.sandbox?.activeDeadlineSeconds !== undefined
221	      ? { activeDeadlineSeconds: config.sandbox.activeDeadlineSeconds }
222	      : {}),
223	    ...(config.sandbox?.readinessPollMs !== undefined
224	      ? { readinessPollMs: config.sandbox.readinessPollMs }
225	      : {}),
226	    ...(config.sandbox?.readinessTimeoutMs !== undefined
227	      ? { readinessTimeoutMs: config.sandbox.readinessTimeoutMs }
228	      : {}),
229	  };
230	  plugins.push(createSandboxK8sPlugin(sandboxOpts));
231	
232	  plugins.push(createIpcServerPlugin());
233	  plugins.push(createLlmProxyAnthropicFormatPlugin());
234	
235	  const orchestratorCfg: Parameters<typeof createChatOrchestratorPlugin>[0] = {
236	    runnerBinary: config.chat?.runnerBinary ?? defaultRunnerBinary(),
237	    chatTimeoutMs: config.chat?.chatTimeoutMs ?? DEFAULT_CHAT_TIMEOUT_MS,
238	  };
239	  if (config.chat?.oneShot !== undefined) {
240	    orchestratorCfg.oneShot = config.chat.oneShot;
241	  }
242	  plugins.push(createChatOrchestratorPlugin(orchestratorCfg));
243	
244	  // ----- 6. tool catalog -------------------------------------------------
245	  // Dispatcher first — it registers `tool:register` / `tool:list`. The
246	  // descriptor-only tool plugins (bash, file-io) call `tool:register` from
247	  // their init. mcp-client also calls `tool:register` from init.
248	  plugins.push(createToolDispatcherPlugin());
249	  plugins.push(createToolBashPlugin());
250	  plugins.push(createToolFileIoPlugin());
251	  plugins.push(createMcpClientPlugin());
252	
253	  // ----- 7. LLM ----------------------------------------------------------
254	  // Throws at init if ANTHROPIC_API_KEY is missing.
255	  const anthropicCfg: Parameters<typeof createLlmAnthropicPlugin>[0] = {};
256	  if (config.anthropic?.model !== undefined) {
257	    anthropicCfg.model = config.anthropic.model;
258	  }
259	  if (config.anthropic?.maxTokens !== undefined) {
260	    anthropicCfg.maxTokens = config.anthropic.maxTokens;
261	  }
262	  plugins.push(createLlmAnthropicPlugin(anthropicCfg));
263	
264	  return plugins;
265	}
